{ id:"ASTRO 320", code:"ASTRO 320", name:"Stellar Astrophysics I", dept:"ASTRO", cat:"General", year:3, units:320, pre:{"and":["ASTRO320","MATH101","PHYS208"]}, co:[], description:"Science Application of physics to stellar formation and stellar evolution; theoretical models and observational comparisons of main sequence stars, white dwarf stars, neutron stars, supernovae, black holes; binary star systems, stellar atmospheres and stellar spectra.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/ASTRO/320" }
{ id:"ASTRO 322", code:"ASTRO 322", name:"Galactic and Extragalactic Astrophysics", dept:"ASTRO", cat:"General", year:3, units:322, pre:{"and":["ASTRO322","MATH101","PHYS208"]}, co:[], description:"Science The interstellar medium and interstellar reddening; galactic structure; kinematics and dynamics of stars in galaxies; quasars; introduction of cosmology.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/ASTRO/322" }
{ id:"ASTRO 429", code:"ASTRO 429", name:"Introduction to Space Physics", dept:"ASTRO", cat:"General", year:4, units:429, pre:null, co:["ASTRO429","PHYS381","ASTRO529"], description:"Science Fundamental concepts, observations, and methods of space physics: introduction to plasma physics including single particle motion, introduction to plasma kinetic theory, fluids, and magnetohydrodynamics; introduction to waves and discontinuities; the Sun, heliosphere, and solar wind; Earth's magnetosphere including space weather, structures and dynamics, the ionosphere, and the aurora; and planetary space environments.", restrictions:"Note: Credit may only be obtained for one of ASTRO 429 or ASTRO 529.", url:"https://apps.ualberta.ca/catalogue/course/ASTRO/429" }
