{ id:"ECON 452", code:"ECON 452", name:"Political Economy", dept:"ECON", cat:"General", year:4, units:452, pre:{"and":["ECON452","ECON281"]}, co:[], description:"Arts Economic analysis of incentives facing citizens, politicians and policymakers, how these incentives are shaped by institutions, and the resulting effects on economic outcomes and policy.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/ECON/452" }
