{ id:"EDPY 302", code:"EDPY 302", name:"Learning and Development from Infancy to Adolescence", dept:"EDPY", cat:"General", year:3, units:302, pre:null, co:["EDPY302","EDU100","EDFX200","PSYCH223","PSYCH323","PSYCH327","CTURE100","CTURE101","CTURE800","CTURE150","CTURE850"], description:"Education This course will include theoretical and practical aspects of physical, cognitive, social and emotional development and learning during the period from infancy to adolescence (0-19 years).", restrictions:"Note: this course may not be taken for credit if credit for PSYCH 223, PSYCH 323 or PSYCH 327 is already awarded. May contain alternative delivery sections; refer to the Tuition and Fees page in the University Regulations section of the Calendar.", url:"https://apps.ualberta.ca/catalogue/course/EDPY/302" }
