{ id:"FS 215", code:"FS 215", name:"Introduction to Film Theory", dept:"FS", cat:"General", year:2, units:215, pre:null, co:[], description:"Arts General survey of major currents and debates in film theory, including early theories on the ontology of the film image, semiotic approaches to film as language, Marxist and psychoanalytic concepts of spectatorship and the film image, the intersections of film and ideology, and the phenomenological theory of film as an embodied experience.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/215" }
{ id:"FS 309", code:"FS 309", name:"Quebec Film", dept:"FS", cat:"General", year:3, units:309, pre:null, co:[], description:"Arts History and aesthetic developments in Quebec film, from 1930s to present.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/309" }
{ id:"FS 310", code:"FS 310", name:"English-Canadian Film", dept:"FS", cat:"General", year:3, units:310, pre:null, co:[], description:"Arts Major trends in English Canadian film, such as documentary, feature film, animation, and experimental film.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/310" }
{ id:"FS 313", code:"FS 313", name:"Transnational Crime Cinema", dept:"FS", cat:"General", year:3, units:313, pre:null, co:[], description:"Arts Examining the ways in which crime and criminality have been represented in narrative cinema across cultures and nationalities.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/313" }
{ id:"FS 315", code:"FS 315", name:"The Western Film", dept:"FS", cat:"General", year:3, units:315, pre:null, co:[], description:"Arts Survey of the cinematic Western from the silent period to the present, with emphasis on the decades between 1930 and 1970.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/315" }
{ id:"FS 316", code:"FS 316", name:"Melodrama and Film", dept:"FS", cat:"General", year:3, units:316, pre:null, co:[], description:"Arts A study of the stylistic, thematic, and ideological features of the melodrama as a film genre with strong ties to the woman's film and the general mode of storytelling of Hollywood cinema.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/316" }
{ id:"FS 317", code:"FS 317", name:"The Gangster Film", dept:"FS", cat:"General", year:3, units:317, pre:null, co:[], description:"Arts Survey of the Hollywood gangster film and related forms from the 1930s to the present.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/317" }
{ id:"FS 318", code:"FS 318", name:"Science Fiction Film", dept:"FS", cat:"General", year:3, units:318, pre:null, co:[], description:"Arts A study of the Science Fiction film genre as an imaginative displacement of social and cultural concerns that define the context in which the films emerge.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/318" }
{ id:"FS 319", code:"FS 319", name:"Film Noir", dept:"FS", cat:"General", year:3, units:319, pre:null, co:[], description:"Arts A study of the stylistic, thematic, and ideological features of the American film genre known as film noir.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/319" }
{ id:"FS 320", code:"FS 320", name:"The French New Wave", dept:"FS", cat:"General", year:3, units:320, pre:null, co:[], description:"Arts Examines the aesthetic, cultural and political principles animating the films of the 1960s cinematic movement known as the French New Wave.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/320" }
{ id:"FS 321", code:"FS 321", name:"Animation", dept:"FS", cat:"General", year:3, units:321, pre:null, co:[], description:"Arts An overview of the development of the animated film in a global context.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/321" }
{ id:"FS 322", code:"FS 322", name:"Gender and Sexuality in Film", dept:"FS", cat:"General", year:3, units:322, pre:null, co:[], description:"Arts Intersections between film and cultural notions and practices of gender and sexuality.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/322" }
{ id:"FS 323", code:"FS 323", name:"Screening Comedy", dept:"FS", cat:"General", year:3, units:323, pre:null, co:[], description:"Arts Examines the history of comedy across cinema, television, and digital platforms, drawing on theories of humor and laughter.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/323" }
{ id:"FS 324", code:"FS 324", name:"Monsters, Slashers and Ghosts", dept:"FS", cat:"General", year:3, units:324, pre:null, co:[], description:"Arts Examines the horror genre from the silent era to the present.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/324" }
{ id:"FS 330", code:"FS 330", name:"Documentary Film", dept:"FS", cat:"General", year:3, units:330, pre:null, co:[], description:"Arts Theory and history of the documentary film, with emphasis on Flaherty, the Documentary Movement in Britain, the National Film Board of Canada, and recent developments in the field.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/330" }
{ id:"FS 331", code:"FS 331", name:"Silent Film", dept:"FS", cat:"General", year:3, units:331, pre:null, co:[], description:"Arts An investigation of silent film treated as a form distinct from sound film.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/331" }
{ id:"FS 333", code:"FS 333", name:"Experimental Film", dept:"FS", cat:"General", year:3, units:333, pre:null, co:[], description:"Arts Avant-garde, abstract and structural film.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/333" }
{ id:"FS 340", code:"FS 340", name:"Making Television: Production Cultures", dept:"FS", cat:"General", year:3, units:340, pre:null, co:[], description:"Arts Examines the cultural and industrial dimensions of televisual production and distribution into the post-network era.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/340" }
{ id:"FS 341", code:"FS 341", name:"Television Genres", dept:"FS", cat:"General", year:3, units:341, pre:null, co:[], description:"Arts Analysis of specific genres within their cultural, historical, and industrial contexts.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/341" }
{ id:"FS 365", code:"FS 365", name:"French Film", dept:"FS", cat:"General", year:3, units:365, pre:null, co:[], description:"Arts An overview of the development of French cinema from the beginning of cinema to the present including major film movements such as Surrealism, Poetic Realism, Cinema Verité, the Nouvelle Vague, and contemporary movements.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/365" }
{ id:"FS 367", code:"FS 367", name:"German Film", dept:"FS", cat:"General", year:3, units:367, pre:null, co:[], description:"Arts Survey of German cinema, with emphasis on the films of the Weimar era (1918-1933) and the New German Cinema of the 1970s.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/367" }
{ id:"FS 368", code:"FS 368", name:"Central and East-European Film", dept:"FS", cat:"General", year:3, units:368, pre:null, co:[], description:"Arts Historical and aesthetic developments in the cinemas of the Czech Republic, Poland, and Hungary from the early years of cinema to the post-1989 period.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/368" }
{ id:"FS 369", code:"FS 369", name:"East Asian Cinema", dept:"FS", cat:"General", year:3, units:369, pre:null, co:[], description:"Arts Survey of East Asian cinemas such as mainland China, Taiwan, Hong Kong, Japan, and South Korea.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/369" }
{ id:"FS 371", code:"FS 371", name:"Contemporary Hollywood", dept:"FS", cat:"General", year:3, units:371, pre:null, co:[], description:"Arts Concentrates on commercial American filmmaking since the 1960s.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/371" }
{ id:"FS 386", code:"FS 386", name:"Screening Race", dept:"FS", cat:"General", year:3, units:386, pre:null, co:[], description:"Arts Examines representations of race, ethnicity, and identity on screen with an emphasis on critical race theories.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/386" }
{ id:"FS 387", code:"FS 387", name:"Film and Technology", dept:"FS", cat:"General", year:3, units:387, pre:null, co:[], description:"Arts An examination of how technology influences the patterns of film production.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/387" }
{ id:"FS 399", code:"FS 399", name:"Special Topics in Film Studies", dept:"FS", cat:"General", year:3, units:399, pre:null, co:[], description:"Arts Prerequisite: FS 100.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/399" }
{ id:"FS 407", code:"FS 407", name:"Topics in Film History", dept:"FS", cat:"General", year:4, units:407, pre:null, co:[], description:"Arts Concentrated study of a specific problem in film history, either a historical period or a problem in historiography.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/407" }
{ id:"FS 410", code:"FS 410", name:"Topics in Filmmakers", dept:"FS", cat:"General", year:4, units:410, pre:null, co:[], description:"Arts Concentrated study of the works of individual filmmakers.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/410" }
{ id:"FS 412", code:"FS 412", name:"Topics in Film Studies", dept:"FS", cat:"General", year:4, units:412, pre:null, co:[], description:"Arts A seminar-based examination of specialized topics in film.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/412" }
{ id:"FS 415", code:"FS 415", name:"Global Television and Screen Cultures", dept:"FS", cat:"General", year:4, units:415, pre:null, co:[], description:"Arts Transnational flows of popular entertainment and their relationship to local and global cultural identities.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/415" }
{ id:"FS 416", code:"FS 416", name:"Analyzing Television", dept:"FS", cat:"General", year:4, units:416, pre:null, co:[], description:"Arts Critical studies of televisual narratives, ideologies, discourses, and audience reception practices.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/416" }
{ id:"FS 480", code:"FS 480", name:"Directed Reading in Film", dept:"FS", cat:"General", year:4, units:480, pre:null, co:[], description:"Arts Prerequisite: consent of Department.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/FS/480" }
{ id:"GENEQ 270", code:"GENEQ 270", name:"Fondations de génétique moléculaire", dept:"GENEQ", cat:"General", year:2, units:270, pre:null, co:[], description:"Faculté Saint-Jean Les concepts de base de l'organisation du matériel génétique et de son expression seront développés à partir d'expériences sur les bactéries et les virus.", restrictions:"Note: Ce cours n'est pas accessible aux étudiants ayant ou postulant des crédits pour GENET 270.", url:"https://apps.ualberta.ca/catalogue/course/GENEQ/270" }
{ id:"GENET 270", code:"GENET 270", name:"Foundations of Molecular Genetics", dept:"GENET", cat:"General", year:2, units:270, pre:{"and":["GENET270","BIOL207","CTURE800","MINAR801"]}, co:[], description:"Science Basic concepts on the organization of genetic material and its expression will be developed from experiments on bacteria and viruses.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/270" }
{ id:"GENET 301", code:"GENET 301", name:"Molecular Genetics of the Eukaryotic Cell", dept:"GENET", cat:"General", year:3, units:301, pre:{"and":["GENET301","GENET270","BIOL201","CELL201"]}, co:[], description:"Science This course explores the genetically tractable model systems of budding yeast and select metazoans to understand eukaryotic cell function and human disease.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/301" }
{ id:"GENET 302", code:"GENET 302", name:"Genetics of Eukaryotic Chromosomes", dept:"GENET", cat:"General", year:3, units:302, pre:{"and":["GENET302","GENET270"]}, co:[], description:"Science Analysis of how the nuclear chromosomes in multicellular eukaryotes are organized, inherited, studied, and manipulated.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/302" }
{ id:"GENET 304", code:"GENET 304", name:"Gene Expression and its Regulation", dept:"GENET", cat:"General", year:3, units:304, pre:{"and":["GENET304","GENET270"]}, co:[], description:"Science The molecular biology of the processes by which the base sequence of genes is expressed as cellular phenotype will be examined.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/304" }
{ id:"GENET 305", code:"GENET 305", name:"Genetic Analysis", dept:"GENET", cat:"General", year:3, units:305, pre:{"and":["GENET305","GENET270","GENET275"]}, co:[], description:"Science Analysis of gene functions in animal model systems.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/305" }
{ id:"GENET 364", code:"GENET 364", name:"Plant Genetics", dept:"GENET", cat:"General", year:3, units:364, pre:{"and":["GENET364","GENET270"]}, co:[], description:"Science This course examines in detail: how to induce mutations in plants by means of chemicals and transgenes; how to use mutagenized and transgenic plant populations for forward and reverse genetic approaches; how to molecularly identify genes defined by mutations in plants; how to infer gene functions and genetic interactions from single and double-mutant phenotypes, respectively, with emphasis on genetic redundancy and functional compensation; and how to visualize gene expression and protein localization with fluorescent proteins.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/364" }
{ id:"GENET 375", code:"GENET 375", name:"Introduction to Molecular Genetics Techniques", dept:"GENET", cat:"General", year:3, units:375, pre:{"and":["GENET375","GENET270","MICRB265"]}, co:[], description:"Science A laboratory course in which students will be introduced to modern techniques in molecular genetics.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/375" }
{ id:"GENET 390", code:"GENET 390", name:"Gene Manipulation", dept:"GENET", cat:"General", year:3, units:390, pre:{"and":["GENET390","BIOL207","BIOCH200","BIOCH220","GENET270"]}, co:[], description:"Science Examination of fundamental techniques employed in molecular biological research relevant to both prokaryotic and eukaryotic systems.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/390" }
{ id:"GENET 412", code:"GENET 412", name:"Genetic Control of Animal Development", dept:"GENET", cat:"General", year:4, units:412, pre:{"and":["GENET412","GENET300","ZOOL303"]}, co:[], description:"Science Gene action during development; identification and analysis of the networks of genetic elements regulating developmental decisions.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/412" }
{ id:"GENET 415", code:"GENET 415", name:"Current Topics in Bacterial Genetics", dept:"GENET", cat:"General", year:4, units:415, pre:{"and":["GENET415","GENET300","MICRB316"]}, co:[], description:"Science The goal of the course is to build knowledge about conserved, fundamental cellular processes uncovered using genetic approaches to study bacteria and to develop an appreciation for the application of this information to the development of technology and the understanding of human diseases.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/415" }
{ id:"GENET 418", code:"GENET 418", name:"Human Genetics", dept:"GENET", cat:"General", year:4, units:418, pre:{"and":["GENET418","GENET300","GENET302"]}, co:[], description:"Science A survey of human genetic variation and mutation in a molecular genetics context.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/418" }
{ id:"GENET 420", code:"GENET 420", name:"Research Techniques in Molecular Genetics", dept:"GENET", cat:"General", year:4, units:420, pre:{"and":["GENET420","GENET390","GENET300","GENET375","BIOL391"]}, co:[], description:"Science A laboratory course teaching modern techniques in molecular biology with emphasis on the analysis of gene expression in animal systems.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/420" }
{ id:"GENET 422", code:"GENET 422", name:"Current Topics in Developmental Genetics", dept:"GENET", cat:"General", year:4, units:422, pre:{"and":["GENET422","GENET412","ZOOL303"]}, co:[], description:"Science Discussion of selected topics in developmental biology with an emphasis on the cellular and genetic mechanisms used to uncover regulatory pathways.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/422" }
{ id:"GENET 424", code:"GENET 424", name:"Ethical Issues in Genetics", dept:"GENET", cat:"General", year:4, units:424, pre:{"and":["GENET424","GENET300"]}, co:[], description:"Science A seminar and discussion course where students will use their existing knowledge of genetics to investigate, evaluate, and discuss how the field of genetics affects society.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENET/424" }
{ id:"GENIE 100", code:"GENIE 100", name:"Réussir en ingénierie", dept:"GENIE", cat:"General", year:1, units:100, pre:null, co:[], description:"Faculté Saint-Jean Introduction à la Faculté de Génie, à la profession d'ingénieur, aux compétences nécessaires pour réussir à l'université et aux fondements du leadership : techniques d'études et autonomie fonctionnelle, gestion du temps et fixation d'objectifs, compétences interpersonnelles, planification de carrière et ingénierie au sein de la société y compris les dimensions éthiques et d'équité, les concepts de développement durable, la gestion de l'environnement et la sécurité publique.", restrictions:"Note: Ce cours n'est pas accessible aux étudiants ayant ou postulant des crédits pour ENGG 100.", url:"https://apps.ualberta.ca/catalogue/course/GENIE/100" }
{ id:"GENIE 130", code:"GENIE 130", name:"Mécanique de l'ingénieur", dept:"GENIE", cat:"General", year:1, units:130, pre:null, co:[], description:"Faculté Saint-Jean Équilibre des systèmes planaires.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENIE/130" }
{ id:"GENIE 160", code:"GENIE 160", name:"Introduction à la conception, à la communication et à la profession d'ingénieur", dept:"GENIE", cat:"General", year:1, units:160, pre:null, co:[], description:"Faculté Saint-Jean Fondements des processus et théories de la conception dans un contexte multidisciplinaire.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GENIE/160" }
{ id:"GEOPH 110", code:"GEOPH 110", name:"Introduction to Earth and Planetary Physics", dept:"GEOPH", cat:"General", year:1, units:110, pre:{"and":["GEOPH110"]}, co:[], description:"Science How do we know what is inside the Earth and planets? What are the dynamic processes that shape the Earth? This course will use a physics-based approach to investigate these questions and develop an explanation for what drives plate tectonics, the origin of planetary magnetic fields, and the causes of hazards such as earthquakes and volcanoes.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/110" }
{ id:"GEOPH 210", code:"GEOPH 210", name:"Structure, Dynamics and Evolution of the Earth and Planetary Interiors", dept:"GEOPH", cat:"General", year:2, units:210, pre:{"and":["GEOPH210","GEOPH110"]}, co:[], description:"Science This course presents an overview of the interior structure, composition, dynamics, and evolution of the Earth, planets, and moons.", restrictions:"Note: credit will be given for only one of GEOPH 110 or GEOPH 210.", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/210" }
{ id:"GEOPH 223", code:"GEOPH 223", name:"Environmental Geophysics", dept:"GEOPH", cat:"General", year:2, units:223, pre:{"and":["GEOPH223"]}, co:[], description:"Science Near-surface geophysical imaging techniques with focus on applications in hydrogeology, glaciology, and environmental studies; rock properties; imaging methods covered include: shallow seismic exploration, magnetic exploration, radiometric techniques, electrical resistivity tomography (ERT); electromagnetic (EM) methods; ground penetrating radar (GPR), application to environmental monitoring, climate change, environmental legislation.", restrictions:"Note: Not available to students in Honors or Specialization Geophysics.", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/223" }
{ id:"GEOPH 224", code:"GEOPH 224", name:"Geophysical Exploration Techniques", dept:"GEOPH", cat:"General", year:2, units:224, pre:{"and":["GEOPH224"]}, co:[], description:"Science Geophysical exploration with focus on techniques relevant to hydrocarbon and mineral exploration; gravity and magnetic exploration techniques; basics of seismic wave propagation in Earth; seismic data processing; the geological interpretation of seismic reflection and refraction data.", restrictions:"Note: Not available to students in Honors or Specialization Geophysics. Note: offered alternate years only. Consult Department for course schedule.", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/224" }
{ id:"GEOPH 325", code:"GEOPH 325", name:"Geophysical Imaging of Earth's Interior", dept:"GEOPH", cat:"General", year:3, units:325, pre:{"and":["GEOPH325","MATH215"]}, co:[], description:"Science Theory of gravity, shape of the earth, nature of the geomagnetic field, magnetic, and electrical exploration methods; factors controlling density, resistivity, magnetic properties of rocks, and planetary studies; applications in environmental geophysics, continental dynamics, and mineral exploration; instrumentation.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/325" }
{ id:"GEOPH 326", code:"GEOPH 326", name:"Seismic Imaging of Earth's Interior", dept:"GEOPH", cat:"General", year:3, units:326, pre:{"and":["GEOPH326","MATH215"]}, co:[], description:"Science Use of reflection and refraction seismology to image the Earth's interior, including application to environmental assessment, mineral and hydrocarbon exploration, geothermal energy, and tectonics; study of current technologies used to acquire, image, and interpret 2D and 3D data sets.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/326" }
{ id:"GEOPH 332", code:"GEOPH 332", name:"Borehole & Laboratory Methods in Geophysics and Petrophysics", dept:"GEOPH", cat:"General", year:3, units:332, pre:{"and":["GEOPH332"]}, co:[], description:"Science Overview of the fundamental physical properties of geophysically important materials; physics involved in the measurement of physical properties in the Earth especially in the context of geophysical well logging and laboratory measurement; integration of measurements with geological and geophysical field observations.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/332" }
{ id:"GEOPH 421", code:"GEOPH 421", name:"Seismology and the Physical Structure of the Earth", dept:"GEOPH", cat:"General", year:4, units:421, pre:null, co:["GEOPH421","MATH215","GEOPH541"], description:"Science Seismology and earthquakes; travel-time, amplitude, and waveform computations; body and surface waves; normal modes and free oscillations; source mechanisms; Earth's structure from inversion of teleseismic observations; seismometers; earthquake hazards and risks.", restrictions:"Note: Credit may be obtained for only one of GEOPH 421 and GEOPH 541.", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/421" }
{ id:"GEOPH 424", code:"GEOPH 424", name:"Electromagnetic Methods in Geophysics", dept:"GEOPH", cat:"General", year:4, units:424, pre:{"and":["GEOPH424","MATH337","PHYS381","GEOPH325"]}, co:["GEOPH424","MATH337","PHYS381","GEOPH325"], description:"Science Theory and application of Maxwell's equations to geophysics; resistivity of rocks, electromagnetic exploration; magnetotellurics, frequency and time domain EM methods, forward and inverse techniques to image crustal and mantle structures.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/424" }
{ id:"GEOPH 426", code:"GEOPH 426", name:"Signal Analysis in Geophysics", dept:"GEOPH", cat:"General", year:4, units:426, pre:{"and":["GEOPH426","MATH311","GEOPH326","PHYS234","GEOPH526"]}, co:[], description:"Science Application of time-series analyses and image-processing techniques to large geophysical data sets; sampling and aliasing of signals; one- and two-dimensional Fourier transforms; the Z transformation; spectral analysis, filtering, and deconvolution; application of 1D and 2D filtering to geophysical data analysis, processing and decomposition.", restrictions:"Note: credit may only be obtained for one of GEOPH 426 and GEOPH 526.", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/426" }
{ id:"GEOPH 431", code:"GEOPH 431", name:"Geophysical Inverse Theory", dept:"GEOPH", cat:"General", year:4, units:431, pre:{"and":["GEOPH431","MATH311","GEOPH531"]}, co:[], description:"Science Quantitative methods to determine the physical properties of the Earth from indirect geophysical observations; formal treatment of geophysical inverse theory; topics include linear and nonlinear inverse problems, regularization techniques, model norms and misfit, tomography, and case histories of interpretation and analysis.", restrictions:"Note: credit may only be obtained for one of GEOPH 431 and GEOPH 531.", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/431" }
{ id:"GEOPH 436", code:"GEOPH 436", name:"Geophysics Field School", dept:"GEOPH", cat:"General", year:4, units:436, pre:{"and":["GEOPH436","GEOPH325","GEOPH536"]}, co:[], description:"Science Students conduct a wide variety of geophysical field measurements and process and interpret the collected data.", restrictions:"Note: credit may only be obtained for one of GEOPH 436 and GEOPH 536.", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/436" }
{ id:"GEOPH 438", code:"GEOPH 438", name:"Seismic Data Processing", dept:"GEOPH", cat:"General", year:4, units:438, pre:{"and":["GEOPH438","GEOPH326","PHYS234","GEOPH426","GEOPH538"]}, co:["GEOPH438","GEOPH326","PHYS234","GEOPH426","GEOPH538"], description:"Science A variety of seismic and ground-penetrating radar data sets are corrected, enhanced, and imaged using commercial and student-written software, to reveal subsurface structures.", restrictions:"Note: credit may only be obtained for one of GEOPH 438 and GEOPH 538.", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/438" }
{ id:"GEOPH 440", code:"GEOPH 440", name:"Global Geodynamics", dept:"GEOPH", cat:"General", year:4, units:440, pre:{"and":["GEOPH440","GEOPH521"]}, co:[], description:"Science Topics to be discussed include plate tectonics; continental breakup and assembly; faulting and earthquakes; mantle and lithosphere rheology; global gravity and Earth's rotation; deep Earth structures; heat transfer and convection in the Earth; dynamics of the core; planetary magnetism and the geodynamo; application to other planets.", restrictions:"Note: credit may only be obtained for one of GEOPH 440 and GEOPH 521.", url:"https://apps.ualberta.ca/catalogue/course/GEOPH/440" }
{ id:"GERM 111", code:"GERM 111", name:"Beginners' German I", dept:"GERM", cat:"General", year:1, units:111, pre:null, co:[], description:"Arts Intended for students with no previous knowledge of the language and designed to develop basic skills: listening, reading, speaking, writing, and intercultural competence.", restrictions:"Note: not to be taken by students with native or near native proficiency, or with German 30 or its equivalents in Canada and other countries. Sections may be offered at an increased rate of fee assessment; refer to the Tuition and Fees page in the University Regulations sections of the Calendar.", url:"https://apps.ualberta.ca/catalogue/course/GERM/111" }
