{ id:"NS 103", code:"NS 103", name:"Canadian Indigenous Language Immersion for Adult Beginners", dept:"NS", cat:"General", year:1, units:103, pre:null, co:[], description:"Native Studies An introduction to a Canadian indigenous language in an immersion context.", restrictions:"Note: This course cannot be used as a substitute for NS 152 nor does it prepare the student for NS 105. A student completing this course may still earn credit in NS 152 at a later date. Not for credit in Faculty of Native Studies degree programs.", url:"https://apps.ualberta.ca/catalogue/course/NS/103" }
{ id:"NS 104", code:"NS 104", name:"The Structure of a Canadian Indigenous Language through Immersion", dept:"NS", cat:"General", year:1, units:104, pre:null, co:[], description:"Native Studies This course, delivered in an immersion context, is designed for beginning speakers or semi-speakers with only a basic knowledge of the particular Canadian indigenous language being focused in a given section.", restrictions:"Note: This course cannot be used as a substitute for NS 152 nor does it necessarily prepare the student for NS 105. A student completing this course may still earn credit in NS 152 or 153 at a later date. Not for credit in Faculty of Native Studies degree programs.", url:"https://apps.ualberta.ca/catalogue/course/NS/104" }
{ id:"NS 110", code:"NS 110", name:"Historical Perspectives in Indigenous Studies", dept:"NS", cat:"General", year:1, units:110, pre:null, co:[], description:"Native Studies A thematic introduction to the historical relationships, colonial contexts, and social, economic, political and cultural patterns that have shaped the contemporary situation of Indigenous peoples in Canada.", restrictions:"Not open to students with credit in NS 210. Sections offered at an increased rate of fee assessment; refer to the Tuition and Fees page in the University Regulations sections of the Calendar.", url:"https://apps.ualberta.ca/catalogue/course/NS/110" }
{ id:"NS 111", code:"NS 111", name:"Contemporary Perspectives in Indigenous Studies", dept:"NS", cat:"General", year:1, units:111, pre:null, co:[], description:"Native Studies An introductory survey of current issues affecting Indigenous peoples in Canada and their efforts to confront their colonial relationships with and within Canadian society.", restrictions:"Not open to students with credit in NS 211. Sections offered at an increased rate of fee assessment; refer to the Tuition and Fees page in the University Regulations sections of the Calendar.", url:"https://apps.ualberta.ca/catalogue/course/NS/111" }
{ id:"NS 115", code:"NS 115", name:"Indigenous Peoples and Technoscience", dept:"NS", cat:"General", year:1, units:115, pre:null, co:[], description:"Native Studies This course introduces students to the long and complicated relationships between science and technology fields, broader dynamics of colonialism, and increasing demands for Indigenous governance of the sciences and technologies that affect them.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/NS/115" }
