{ id:"NS 161", code:"NS 161", name:"Countering Stereotypes of Indigenous Peoples", dept:"NS", cat:"General", year:1, units:161, pre:null, co:[], description:"Native Studies This course pulls the rug from underneath settler-based constructions of Indigeneity.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/NS/161" }
