{ id:"NS 201", code:"NS 201", name:"Indigenous | Canada: Looking Forward/Looking Back", dept:"NS", cat:"General", year:2, units:201, pre:null, co:[], description:"Native Studies For students from faculties outside the Faculty of Native Studies with an interest in acquiring a basic familiarity with Indigenous/non-Indigenous relationships.", restrictions:"Not open to students with credit in NS 200. Not designed for Native Studies majors. Sections offered at an increased rate of fee assessment; refer to the Tuition and Fees page in the University Regulations sections of the Calendar.", url:"https://apps.ualberta.ca/catalogue/course/NS/201" }
