{ id:"PHYS 146", code:"PHYS 146", name:"Fluids and Waves", dept:"PHYS", cat:"General", year:1, units:146, pre:{"and":["PHYS146","PHYS124","MATH118","MATH115","PHYS126","SCI100"]}, co:["PHYS146","PHYS124","MATH118","MATH115","PHYS126","SCI100"], description:"Science A calculus-based course for students majoring in the physical sciences.", restrictions:"Note: MATH 115 is not acceptable as a co-requisite but may be used as a pre-requisite in place of MATH 118 or 146. Note: Credit may be obtained for only one of PHYS 126, 130, 146 or SCI 100. Note: To proceed to PHYS 146 after taking PHYS 124, it is strongly recommended that a minimum grade of B- be achieved in PHYS 124.", url:"https://apps.ualberta.ca/catalogue/course/PHYS/146" }
{ id:"PHYS 181", code:"PHYS 181", name:"Relativity, Electricity and Magnetism", dept:"PHYS", cat:"General", year:1, units:181, pre:{"and":["PHYS181","PHYS124","MATH118"]}, co:["PHYS181","PHYS124","MATH118"], description:"Science This calculus-based course covers introductory electromagnetism including: electric forces and fields, electric potential, capacitance, DC circuits, magnetic forces and fields, magnetic fields from currents, Faraday's Law of induction, electromagnetism, and light.", restrictions:"Note: To proceed to PHYS 181 after taking PHYS 124, it", url:"https://apps.ualberta.ca/catalogue/course/PHYS/181" }
{ id:"PHYS 208", code:"PHYS 208", name:"Aspects of Modern Physics", dept:"PHYS", cat:"General", year:2, units:208, pre:{"and":["PHYS208","PHYS124","PHYS144","PHYS126","PHYS146","PHYS181","PHYS130","MATH100","PHYS271"]}, co:[], description:"Science Experimental evidence for limitations of classical physics; Einstein's special theory of relativity; length contraction; time dilation; twin paradox; equivalence of mass and energy; relativistic mass and momentum; the photo-electric effect, the Compton effect, X-ray production and electron diffraction; a discussion of the Heisenberg uncertainty principle and the Schrödinger equation including applications of one dimensional potential wells and barriers; tunnelling; the simple harmonic oscillator; atomic physics; hydrogen atom; periodic table.", restrictions:"Note: This course may not be taken for credit if credit has already been obta", url:"https://apps.ualberta.ca/catalogue/course/PHYS/208" }
{ id:"PHYS 230", code:"PHYS 230", name:"Electricity and Magnetism", dept:"PHYS", cat:"General", year:2, units:230, pre:{"and":["PHYS230","PHYS130","MATH100","MATH101","PHYS181"]}, co:["PHYS230","PHYS130","MATH100","MATH101","PHYS181"], description:"Science Electric fields, Gauss' Law; electric potential; capacitance and dielectrics; electric current and resistance; magnetic fields, Ampere's Law; Faraday's Law; inductance; magnetic properties of matter.", restrictions:"Note: Restricted to Engineering students. Other students who take this course will receive 3 units. Credit can normally be obtained for only one of PHYS 181, 230, or 281.", url:"https://apps.ualberta.ca/catalogue/course/PHYS/230" }
{ id:"PHYS 234", code:"PHYS 234", name:"Introductory Computational Physics", dept:"PHYS", cat:"General", year:2, units:234, pre:{"and":["PHYS234","PHYS146","PHYS181","MATH118","MATH334"]}, co:["PHYS234","PHYS146","PHYS181","MATH118","MATH334"], description:"Science An introductory course on using computer based methods to solve physics problems, especially those that do not have analytical solutions or require great effort to find it.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/234" }
{ id:"PHYS 244", code:"PHYS 244", name:"Classical Mechanics I", dept:"PHYS", cat:"General", year:2, units:244, pre:{"and":["PHYS244","PHYS124","PHYS144","MATH102","MATH201","MATH334","MATH336"]}, co:["PHYS244","PHYS124","PHYS144","MATH102","MATH201","MATH334","MATH336"], description:"Science An intermediate course in classical mechanics, which covers several applications that are critical to a wide variety of different fields of physics including: simple, damped, and driven harmonic oscillators; coupled oscillators, conservative forces, and energy.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/244" }
{ id:"PHYS 261", code:"PHYS 261", name:"Physics of Energy", dept:"PHYS", cat:"General", year:2, units:261, pre:{"and":["PHYS261","PHYS124","PHYS144","PHYS126","PHYS146","PHYS181","PHYS130","MATH100"]}, co:[], description:"Science Energy in its various forms; conservation of energy; basic thermodynamics of ideal gases and phase changes; heat engines and refrigerators; consumption of energy resources; space heating and heat transfer; radioactivity; nuclear fission and nuclear power; alternative and renewable energy resources.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/261" }
{ id:"PHYS 271", code:"PHYS 271", name:"Introduction to Modern Physics", dept:"PHYS", cat:"General", year:2, units:271, pre:{"and":["PHYS271","PHYS124","PHYS144","MATH201","MATH334","MATH336","MATH102"]}, co:["PHYS271","PHYS124","PHYS144","MATH201","MATH334","MATH336","MATH102"], description:"Science This course covers the emergence of modern physics through revisions to the Newtonian worldview and the development of quantum mechanics.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/271" }
{ id:"PHYS 281", code:"PHYS 281", name:"Electricity and Magnetism", dept:"PHYS", cat:"General", year:2, units:281, pre:{"and":["PHYS281","PHYS124","PHYS144","PHYS126","PHYS146","PHYS130","MATH209","PHYS181"]}, co:["PHYS281","PHYS124","PHYS144","PHYS126","PHYS146","PHYS130","MATH209","PHYS181"], description:"Science Electric fields; Gauss' law; electric potential; capacitance and dielectrics; electric current and resistance; DC circuits; magnetic fields; Ampere's Law; Faraday's Law; inductance; magnetic properties of matter, AC circuits; Maxwell's equations; electromagnetic waves.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/281" }
