{ id:"PHYS 294", code:"PHYS 294", name:"General Physics Laboratory", dept:"PHYS", cat:"General", year:2, units:294, pre:{"and":["PHYS294","MATH100","PHYS124","PHYS144","PHYS126","PHYS146","PHYS181","PHYS130","PHYS295"]}, co:[], description:"Science Introduction to experimental physics through select, classic experiments in physics from the 19th through 21st centuries performed using contemporary instrumentation when possible.", restrictions:"Note: PHYS 294 will not count towards degree credit for Honors programs offered by the physics department (including physics, geophysics, astrophysics and mathematical physics). Students enrolled in those Honors programs are re", url:"https://apps.ualberta.ca/catalogue/course/PHYS/294" }
{ id:"PHYS 295", code:"PHYS 295", name:"Experimental Physics I", dept:"PHYS", cat:"General", year:2, units:295, pre:{"and":["PHYS295","MATH101","PHYS124","PHYS144","PHYS126","PHYS146","PHYS181","PHYS130","PHYS294"]}, co:[], description:"Science Contemporary methods of experimental physics with measurements from classical and modern physics.", restrictions:"Note: To proceed to PHYS 295 after taking PHYS 126 a minimum grade of B+ in PHYS 126 and some experience of computer programming are strongly recommended. Students may only receive credit in one of PHYS 294 or PHYS 295.", url:"https://apps.ualberta.ca/catalogue/course/PHYS/295" }
{ id:"PHYS 297", code:"PHYS 297", name:"Experimental Physics II", dept:"PHYS", cat:"General", year:2, units:297, pre:{"and":["PHYS297","PHYS295","PHYS271","MATH101"]}, co:["PHYS297","PHYS295","PHYS271","MATH101"], description:"Science Contemporary methods of experimental physics with measurements from classical and modern physics.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/297" }
{ id:"PHYS 301", code:"PHYS 301", name:"Particles, Nuclei, and the Cosmos", dept:"PHYS", cat:"General", year:3, units:301, pre:{"and":["PHYS301","PHYS208","MATH101","SCI100"]}, co:[], description:"Science Relativity; properties and structure of the nucleus; radioactivity, carbon dating, tracer techniques; nuclear fission; fusion; nuclear reactors; elementary particles and particle accelerators; standard model; astrophysics; cosmology.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/301" }
{ id:"PHYS 308", code:"PHYS 308", name:"Statistical, Molecular, and Solid State Physics", dept:"PHYS", cat:"General", year:3, units:308, pre:{"and":["PHYS308","PHYS208","MATH101","SCI100"]}, co:[], description:"Science Classical and quantum statistics; fermions; bosons; molecular structure and spectra; molecular bonding; vibrational and rotational states; absorption; stimulated emission; population inversion; lasers; solid state physics; crystal structure; free-electron gas in metals; band theory of solids; semiconductors; semiconductor devices; superconductivity.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/308" }
{ id:"PHYS 310", code:"PHYS 310", name:"Thermodynamics and Kinetic Theory", dept:"PHYS", cat:"General", year:3, units:310, pre:{"and":["PHYS310","PHYS124","PHYS144","PHYS126","PHYS146","PHYS181","PHYS130","MATH209"]}, co:["PHYS310","PHYS124","PHYS144","PHYS126","PHYS146","PHYS181","PHYS130","MATH209"], description:"Science Temperature: heat, work, and the first law of thermodynamics; entropy and the second law, enthalpy, Helmholtz and Gibbs free energy; thermodynamic equilibrium criteria; Maxwell's relations, phase transitions; elementary kinetic theory of gases.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/310" }
{ id:"PHYS 311", code:"PHYS 311", name:"Statistical Physics", dept:"PHYS", cat:"General", year:3, units:311, pre:{"and":["PHYS311","PHYS310","PHYS271","MATH209"]}, co:[], description:"Science Quantum states, probability distributions, temperature and entropy; canonical ensemble and the partition function; ideal gases, paramagnets; blackbody radiation.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/311" }
{ id:"PHYS 362", code:"PHYS 362", name:"Optical Physics", dept:"PHYS", cat:"General", year:3, units:362, pre:{"and":["PHYS362","PHYS181","MATH209"]}, co:[], description:"Science Electromagnetic waves; polarization and birefringence; dispersion of light in materials; Fresnel equations for reflection and transmission; multiple-beam interference; Fraunhofer and Fresnel diffraction; Fourier optics; coherence theory; optical imaging and instruments; introduction to laser physics, quantum optics, and selected current topics.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/362" }
{ id:"PHYS 364", code:"PHYS 364", name:"Environmental Physics II", dept:"PHYS", cat:"General", year:3, units:364, pre:{"and":["PHYS364","PHYS261","MATH101","SCI100"]}, co:[], description:"Science Calculation of pollutant concentrations using principles of materials balance; vertical variation of pressure and temperature in the atmosphere; atmospheric stability and the dispersal of air pollutants; water vapour and humidity; blackbody radiation and Earth's global energy balance; molecular absorption of electromagnetic radiation; the ozone problem; the radon problem.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/364" }
{ id:"PHYS 372", code:"PHYS 372", name:"Quantum Mechanics A", dept:"PHYS", cat:"General", year:3, units:372, pre:{"and":["PHYS372","PHYS244","PHYS271","MATH334"]}, co:[], description:"Science Origins of quantum mechanics; wave functions; Schrodinger equation and its application to one dimensional systems, postulates and physical interpretation of quantum mechanics; orbital angular momentum, central potentials and three-dimensional systems.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/372" }
{ id:"PHYS 381", code:"PHYS 381", name:"Electromagnetic Theory I", dept:"PHYS", cat:"General", year:3, units:381, pre:{"and":["PHYS381","PHYS181","MATH201","MATH209"]}, co:[], description:"Science Review of scalar and vector fields; Gauss and Stokes theorems; curvilinear coordinates; Dirac delta function; electrostatic field and potential; electrostatic energy; conductors, capacitors; Laplace's equation; boundary value problems; methods of images; multipoles; electrostatic field in matter; polarization; displacement; linear dielectrics; magnetostatic field; Biot-Savart and Ampere's law; vector potential; magnetostatic field in matter; magnetization; linear and nonlinear magnetic media.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/381" }
