{ id:"PHYS 420", code:"PHYS 420", name:"Computational Physics", dept:"PHYS", cat:"General", year:4, units:420, pre:{"and":["PHYS420","PHYS234","PHYS381","MATH337","ECE341","PHYS311","PHYS372","PHYS472","PHYS481"]}, co:["PHYS420","PHYS234","PHYS381","MATH337","ECE341","PHYS311","PHYS372","PHYS472","PHYS481"], description:"Science Basic principles; computational methods selected from finite-differences, matrix manipulation, variational techniques, discrete transforms, stochastic methods, lattice techniques; as applied to topics selected from nonlinear mechanics, chaotic systems; electrodynamics; wave propagation; statistical physics; quantum mechanics; condensed matter.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/420" }
