{ id:"PHYS 481", code:"PHYS 481", name:"Electromagnetic Theory II", dept:"PHYS", cat:"General", year:4, units:481, pre:{"and":["PHYS481","PHYS381","MATH337","ECE341"]}, co:[], description:"Science Electromotive force; Faraday's law; inductance; Maxwell's equations in free space and in matter; electromagnetic potentials; gauges; energy and momentum conservation laws; plane waves in vacuum, in nonconducting and in conducting media; reflection and refraction of electromagnetic waves; dispersion, wave guides; dipole radiation; radiation due to moving charge; radiation reaction.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PHYS/481" }
