{ id:"PSSTC 100", code:"PSSTC 100", name:"Rôle et Responsabilités d'un Préposé aux soins de santé", dept:"PSSTC", cat:"General", year:1, units:100, pre:null, co:[], description:"Faculté Saint-Jean Tout au long de ce cours, vous vous pencherez sur le rôle et les responsabilités d'un aide-soignant travaillant dans des cadres d'emplois variés.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSSTC/100" }
{ id:"PSSTC 101", code:"PSSTC 101", name:"Communication & Documentation dans un environnement des soins de santé", dept:"PSSTC", cat:"General", year:1, units:101, pre:null, co:[], description:"Faculté Saint-Jean Ce cours mettra l'accent sur le rôle et les responsabilités de l'aide-soignant dans une communication efficace en tant que membre d'une équipe de soins axés sur la collaboration.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSSTC/101" }
{ id:"PSSTC 110", code:"PSSTC 110", name:"Le corps humain, la santé et la maladie chronique", dept:"PSSTC", cat:"General", year:1, units:110, pre:null, co:[], description:"Faculté Saint-Jean Dans ce cours, vous étudierez les systèmes qui composent le corps humain et discuterez des étapes-clés de la croissance et du développement au cours d'une vie.", restrictions:"Note: Les étudiants doivent obtenir une note de passage d'au moins B- afin de pouvoir continuer dans le programme.", url:"https://apps.ualberta.ca/catalogue/course/PSSTC/110" }
{ id:"PSSTC 120", code:"PSSTC 120", name:"Prodiguer des soins centrés sur la personne", dept:"PSSTC", cat:"General", year:1, units:120, pre:null, co:[], description:"Faculté Saint-Jean Dans ce cours, le participant apprendra comment appuyer les clients dans le maintien de leur indépendance tout en répondant à leurs besoins selon des plans de soins individuels.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSSTC/120" }
{ id:"PSSTC 121", code:"PSSTC 121", name:"Satisfaire aux besoins complexes", dept:"PSSTC", cat:"General", year:1, units:121, pre:null, co:[], description:"Faculté Saint-Jean Ce cours s'appuie sur les compétences et concepts fondamentaux introduits dans les cours précédents et présente également de nouvelles compétences aux participants.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSSTC/121" }
{ id:"PSSTC 122", code:"PSSTC 122", name:"Activités spéciales pour clients ayant divers problèmes de santé", dept:"PSSTC", cat:"General", year:1, units:122, pre:null, co:[], description:"Faculté Saint-Jean La section complète sur les besoins de soins et de confort des clients ayant reçu un diagnostic de démence est un élément fondamental de ce cours.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSSTC/122" }
{ id:"PSSTC 150", code:"PSSTC 150", name:"Stage clinique intégré I", dept:"PSSTC", cat:"General", year:1, units:150, pre:null, co:[], description:"Faculté Saint-Jean Sous la direction d'un professionnel de la santé dûment accrédité, le participant travaillera dans un milieu de soins prolongés, tel qu'un centre d'appui à la vie autonome, un centre d'appui à la vie autonome désigné, une résidence pour personnes âgées, un centre de soins de longue durée, ou un foyer d'accueil, pour y offrir des soins et un soutien axés sur la personne pour les clients et leurs familles.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSSTC/150" }
{ id:"PSSTC 151", code:"PSSTC 151", name:"Stage clinique intégré  II", dept:"PSSTC", cat:"General", year:1, units:151, pre:null, co:[], description:"Faculté Saint-Jean Sous la direction d'un professionnel de la santé dûment accrédité, les participants travailleront dans un milieu de soins de santé tel qu'un centre de soins de longue durée ou de soins intensifs, pour y offrir des soins et un soutien axés sur la personne pour les clients et leurs familles.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSSTC/151" }
{ id:"PSSTC 160", code:"PSSTC 160", name:"Stage clinique intégré III", dept:"PSSTC", cat:"General", year:1, units:160, pre:null, co:[], description:"Faculté Saint-Jean Sous la direction d'un professionnel de la santé dûment accrédité et jumelé à un prestataire de soins de santé non règlementé, les participants travailleront dans un milieu de soins de santé tel qu'un centre de soins de longue durée ou de soins intensifs, pour y offrir des soins et un soutien axés sur la personne pour les clients et leurs familles.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSSTC/160" }
