{ id:"PSYCE 105", code:"PSYCE 105", name:"Comportement social et individuel", dept:"PSYCE", cat:"General", year:1, units:105, pre:null, co:[], description:"Faculté Saint-Jean Introduction à l'étude de l'individualité humaine, de la personnalité et des processus sociaux.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCE/105" }
