{ id:"PSYCH 354", code:"PSYCH 354", name:"Foundations of Cognitive Science", dept:"PSYCH", cat:"General", year:3, units:354, pre:{"and":["PSYCH354","PSYCH213","STAT151","PSYCH258"]}, co:[], description:"Science An introduction to the theories and research practices of cognitive science by examining contributions of cognitive psychology, artificial intelligence, linguistics, and neuroscience to a variety of research areas.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/354" }
