{ id:"PSYCH 367", code:"PSYCH 367", name:"Perception", dept:"PSYCH", cat:"General", year:3, units:367, pre:{"and":["PSYCH367","PSYCH275"]}, co:[], description:"Science An introduction to theoretical and experimental issues associated with sensory and perceptual experience.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/367" }
