{ id:"PSYCH 375", code:"PSYCH 375", name:"Introduction to Cognitive Neuroscience", dept:"PSYCH", cat:"General", year:3, units:375, pre:{"and":["PSYCH375","PSYCH275"]}, co:[], description:"Science Brain basis of human cognition studied using a diverse range of techniques, with a focus on measures of brain activity such as functional neuroimaging and electrophysiology and on experimental findings in neurologically intact participants.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/375" }
{ id:"PSYCH 377", code:"PSYCH 377", name:"Human Neuropsychology", dept:"PSYCH", cat:"General", year:3, units:377, pre:{"and":["PSYCH377","PSYCH275"]}, co:[], description:"Science Brain basis of cognition viewed through the lens of patients with brain damage.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/377" }
