{ id:"PSYCH 398", code:"PSYCH 398", name:"Individual Research", dept:"PSYCH", cat:"General", year:3, units:398, pre:{"and":["PSYCH398"]}, co:[], description:"Arts A course designed to allow the senior undergraduate student the opportunity to pursue a supervised research project in greater depth than the classroom structure permits.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/398" }
{ id:"PSYCH 399", code:"PSYCH 399", name:"Honors Thesis I: Research Apprenticeship", dept:"PSYCH", cat:"General", year:3, units:399, pre:{"and":["PSYCH399","PSYCH490"]}, co:[], description:"Arts Under the direction of a Faculty member, students pursue a topic of interest leading to the development of a thesis proposal (the proposed research is completed in PSYCH 490).", restrictions:"Note: Must be taken twice in the first year in the Honors program. In the first year in the Honors Program students must complete a formal presentation (i.e., oral or poster) about their research progress. This is typically done at the annual Honors Psychology Conference. Other public venues can fulfill this requirement, with approval by the Honors advisor. Prerequisite: A committed Thesis Supervisor. Restricted to, and required of, students in their first year in the Arts Honors Psychology program. [Faculty of Arts]", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/399" }
{ id:"PSYCH 400", code:"PSYCH 400", name:"Honors Seminar II", dept:"PSYCH", cat:"General", year:4, units:400, pre:{"and":["PSYCH400","PSYCH300"]}, co:[], description:"Arts A continuation of PSYCH 300, with an emphasis on the development of professional skills.", restrictions:"Note: Must be taken twice in the second year in the Honors program. [Faculty of Arts]", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/400" }
