{ id:"PSYCH 425", code:"PSYCH 425", name:"Developmental Cognitive Neuroscience", dept:"PSYCH", cat:"General", year:4, units:425, pre:{"and":["PSYCH425","PSYCH212","PSYCH213","STAT151","PSYCH323"]}, co:[], description:"Science An in-depth review and analysis of developmental cognitive neuroscience methods and principles of brain development and neuroplasticity, and their application to particular domains of development (e.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/425" }
