{ id:"PSYCH 431", code:"PSYCH 431", name:"Theory and Practice of Psychometrics", dept:"PSYCH", cat:"General", year:4, units:431, pre:{"and":["PSYCH431","PSYCH213","STAT151","PSYCH333"]}, co:[], description:"Arts The nature of psychological tests: some practical work in administration, scoring and interpretation of tests.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/431" }
