{ id:"PSYCH 440", code:"PSYCH 440", name:"Advanced Topics in Culture and Psychology", dept:"PSYCH", cat:"General", year:4, units:440, pre:{"and":["PSYCH440","PSYCH341"]}, co:[], description:"Arts An in-depth review and analysis of research in an area of cultural psychology.", restrictions:"Note: Consult the Department of Psychology website for the topics offered and any additional prerequisites. [Faculty of Arts]", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/440" }
{ id:"PSYCH 441", code:"PSYCH 441", name:"Advanced Cultural Psychology", dept:"PSYCH", cat:"General", year:4, units:441, pre:{"and":["PSYCH441","PSYCH341"]}, co:[], description:"Arts In-depth review of the theoretical and methodological bases of cultural psychology, with a focus on specific topics or issues in cultural psychology.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/441" }
{ id:"PSYCH 443", code:"PSYCH 443", name:"Social Cognition", dept:"PSYCH", cat:"General", year:4, units:443, pre:{"and":["PSYCH443","PSYCH213","STAT151","PSYCH241"]}, co:[], description:"Arts Advanced treatment of topics in the study of how we think about the world of persons and events.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/443" }
