{ id:"PSYCH 448", code:"PSYCH 448", name:"Group Processes and Intergroup Relations", dept:"PSYCH", cat:"General", year:4, units:448, pre:{"and":["PSYCH448","PSYCH405","PSYCH213","STAT151","STAT161"]}, co:[], description:"Arts In-depth examination of research and theory related to the social psychological processes within and between groups.", restrictions:"Note: Not open to students with credit in PSYCH 405 Topic: Group Processes and Intergroup Relations. Prerequisites: PSYCH 213 or STAT 151 or STAT 161, and one 300-level PSYCH course. [Faculty of Arts]", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/448" }
{ id:"PSYCH 449", code:"PSYCH 449", name:"Psychology of Teaching and Learning", dept:"PSYCH", cat:"General", year:4, units:449, pre:{"and":["PSYCH449","PSYCH405","PSYCH213","STAT151","STAT161","PSYCH104"]}, co:[], description:"Arts This course examines what research in psychology and education can tell us about how learning in university takes place, and how this knowledge can be applied to the teaching and learning in undergraduate psychology courses.", restrictions:"Note: Not open to students with credit in PSYCH 405 Topic: Psychology of Teaching and Learning. Prerequisites: PSYCH 213 or STAT 151 or STAT 161, one 300-level PSYCH course, and a 3.0 GPA on all attempted PSYCH courses (excluding PSYCH 104 and 105). [Faculty of Arts]", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/449" }
{ id:"PSYCH 452", code:"PSYCH 452", name:"Minds and Machines", dept:"PSYCH", cat:"General", year:4, units:452, pre:{"and":["PSYCH452","PSYCH354"]}, co:[], description:"Science Computational models are playing an increasingly important role in cognitive psychology.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/452" }
{ id:"PSYCH 453", code:"PSYCH 453", name:"Social Neuroscience", dept:"PSYCH", cat:"General", year:4, units:453, pre:{"and":["PSYCH453","PSYCH403","PSYCH213","STAT151"]}, co:[], description:"Science Survey of theories and research on social neuroscience.", restrictions:"Note: Not open to students with credit in PSYCH 403 Topic: Social Neuroscience. Prerequisites: PSYCH 213 or STAT 151 or 161, and one 300-level PSYCH course. [Faculty of Science]", url:"https://apps.ualberta.ca/catalogue/course/PSYCH/453" }
