{ id:"SOCIE 212", code:"SOCIE 212", name:"Théories sociologiques classiques", dept:"SOCIE", cat:"General", year:2, units:212, pre:null, co:[], description:"Faculté Saint-Jean Fondements et impacts des travaux de Marx, Weber, Durkheim et d'autres sur la sociologie et à la théorie sociale.", restrictions:"Note: Ce cours n'est pas accessible aux étudiants ayant ou postulant des crédits pour SOC 212.", url:"https://apps.ualberta.ca/catalogue/course/SOCIE/212" }
