{ id:"SPH 416", code:"SPH 416", name:"One-Health", dept:"SPH", cat:"General", year:4, units:416, pre:{"and":["SPH416","SPH516","AFNS416","CTURE850"]}, co:[], description:"School of Public Health One Health is an emerging paradigm in public and veterinary health which recognizes that human, animal and environmental health are interlinked.", restrictions:"students may not register for credit (see SPH 516). Credit will only be given for one of AFNS 416, 516 or SPH 416, 516. Prerequisite: 3 units in MICRB or PHYSL.", url:"https://apps.ualberta.ca/catalogue/course/SPH/416" }
