{ id:"STAT 181", code:"STAT 181", name:"Introduction to Combinatorics and Probability", dept:"STAT", cat:"General", year:1, units:181, pre:{"and":["STAT181","MATH101","MATH125","STAT265","STAT281","MATH181"]}, co:["STAT181","MATH101","MATH125","STAT265","STAT281","MATH181"], description:"Science Induction; principles of counting, multinomial coefficients, negative binomial distribution; maximum likelihood estimation, probability axioms; conditional probability, Bayes' rule; independence; probability mass, distribution, and moment generating functions; strong law of large numbers; conditional expectation estimators; gambler's ruin; transience and recurrence; compound processes; applications.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/181" }
