{ id:"STAT 252", code:"STAT 252", name:"Introduction to Applied Statistics II", dept:"STAT", cat:"General", year:2, units:252, pre:{"and":["STAT252","STAT141","SCI151","AREC313","STAT368"]}, co:[], description:"Science Methods in applied statistics including regression techniques, analysis of variance and covariance, and methods of data analysis.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/252" }
