{ id:"STAT 276", code:"STAT 276", name:"Statistics for Data Science", dept:"STAT", cat:"General", year:2, units:276, pre:{"and":["STAT276","STAT281","STAT265","MATH117","MATH216","STAT266"]}, co:["STAT276","STAT281","STAT265","MATH117","MATH216","STAT266"], description:"Science Fundamental principles of statistical learning and inference for data science Understanding of types of analytics, probability, variability, relationship between variables, probability distributions, law of large numbers, Central Limit Theorem, hypothesis testing and statistical significance, and elementary theory of regression.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/276" }
{ id:"STAT 281", code:"STAT 281", name:"Probability by Counting and Queuing", dept:"STAT", cat:"General", year:2, units:281, pre:null, co:["STAT281","MATH209","STAT181","STAT265","STAT371"], description:"Science Review of binomial and negative binomial distributions; continuous random variables; uniform, exponential, and gamma distributions; conditional probability; properties of conditional expectation; stochastic processes; finite-dimensional distributions, Poisson approximation; Poisson measures; counting processes, Markov queues, customer time in queues; steady-state distributions; applications.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/281" }
{ id:"STAT 337", code:"STAT 337", name:"Biostatistics", dept:"STAT", cat:"General", year:3, units:337, pre:{"and":["STAT337","STAT151","STAT161","SCI151","STAT252","AREC313","STAT368"]}, co:[], description:"Science Methods of data analysis useful in Biostatistics including analysis of variance and covariance and nested designs, multiple regression, logistic regression and log-linear models.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/337" }
{ id:"STAT 353", code:"STAT 353", name:"Life Contingencies I", dept:"STAT", cat:"General", year:3, units:353, pre:{"and":["STAT353","MATH253","STAT265","STAT281"]}, co:[], description:"Science Time at death random variables, continuous and discrete insurances, endowments and varying annuities, net premiums and reserves.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/353" }
{ id:"STAT 361", code:"STAT 361", name:"Sampling Techniques", dept:"STAT", cat:"General", year:3, units:361, pre:{"and":["STAT361","STAT266","STAT276","STAT235"]}, co:[], description:"Science Simple random sampling from finite populations, stratified sampling, regression estimators, cluster sampling.", restrictions:"Note: This course may only be offered in alternate years.", url:"https://apps.ualberta.ca/catalogue/course/STAT/361" }
{ id:"STAT 368", code:"STAT 368", name:"Introduction to Design and Analysis of Experiments", dept:"STAT", cat:"General", year:3, units:368, pre:{"and":["STAT368","STAT266","STAT276","STAT235"]}, co:[], description:"Science Basic principles of experimental design, completely randomized design-one way ANOVA and ANCOVA, randomized block design, Latin square design, Multiple comparisons.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/368" }
