{ id:"STAT 378", code:"STAT 378", name:"Applied Regression Analysis", dept:"STAT", cat:"General", year:3, units:378, pre:{"and":["STAT378","STAT266","STAT276","STAT235"]}, co:[], description:"Science Simple linear regression analysis, inference on regression parameters, residual analysis, prediction intervals, weighted least squares.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/378" }
{ id:"STAT 413", code:"STAT 413", name:"Computing for Data Science", dept:"STAT", cat:"General", year:4, units:413, pre:{"and":["STAT413","STAT265","STAT281","STAT266","STAT276"]}, co:[], description:"Science Survey of contemporary languages/environments suitable for algorithms of Statistics and Data Science.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/413" }
{ id:"STAT 432", code:"STAT 432", name:"Survival Analysis", dept:"STAT", cat:"General", year:4, units:432, pre:{"and":["STAT432","STAT372"]}, co:[], description:"Science Survival models, model estimation from complete and incomplete data samples, parametric survival models with concomitant variables, estimation of life tables from general population data.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/432" }
