{ id:"STAT 441", code:"STAT 441", name:"Statistical Methods for Learning and Data Mining", dept:"STAT", cat:"General", year:4, units:441, pre:{"and":["STAT441","STAT378"]}, co:[], description:"Science Review of linear and nonlinear regression and brief introduction to generalized linear models, the course covers selected methods of dimension reduction (principal components, factor analysis, canonical correlations), of unsupervised (clustering, multidimensional scaling ordination) and supervised classification (discriminant analysis, logistic regression, nearest neighbours - including, among others, the machine learning methods like classification trees, neural networks, and support vector machines).", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/441" }
{ id:"STAT 453", code:"STAT 453", name:"Risk Theory", dept:"STAT", cat:"General", year:4, units:453, pre:{"and":["STAT453","STAT371","STAT281"]}, co:[], description:"Science Classical ruin theory, individual risk models, collective risk models, models for loss severity: parametric models, tail behavior, models for loss frequency, mixed Poisson models; compound Poisson models, convolutions and recursive methods, probability and moment generating functions.", restrictions:"", url:"https://apps.ualberta.ca/catalogue/course/STAT/453" }
